  while(cin>>N>>M){

    int Min[MAX_N]={},Max[MAX_N]={};

    if(M==0&&N==0)break;

    for(int i=0;i<M;i++){

      int p,k,id;

      cin>>p>>k;

      for(int j=0;j<k;j++){

        cin>>id;

        id--;

        if(k==1){

          Min[id]+=p;

        }

        Max[id]+=p;

      }

    }



    int mini=1e9,maxm=-1e9,ans=0;



    for(int i=0;i<N;i++){



      if(Max[i]>mini)

        ans=max(ans, abs(Max[i]-mini) );



      if(maxm>Min[i])

