#include<cstdio>

#include<new>

#include<cstdlib>

#include<cstring>

using namespace std;

typedef struct node;

typedef node * tree;

int bianliang=0;

struct node

{

       int data;

       tree lchild,rchild;

};

tree root;

void build(tree &p,int n)

{

     if(p)

     {

          if(n<p->data)

          build(p->lchild,n);

          if(n>p->data)

          build(p->rchild,n);

     }

     else

     {

         p=new node;

         p->data=n;

         p->lchild=NULL;

         p->rchild=NULL;

     }

}    

void find(tree w,int x)

{

     if(w==NULL)bianliang=-1;

     else if(x==w->data)

       bianliang=1;

     else if(x<w->data)

       find(w->lchild,x);

     else if(x>w->data)

       find(w->rchild,x);

}

void beforeorder(tree q)

{

   if(q==NULL)return;

     cout<<" "<<q->data;

     beforeorder(q->lchild);

     beforeorder(q->rchild);

}

void midorder(tree q)

{

     if(q==NULL)return;

       midorder(q->lchild);

       cout<<" "<<q->data;

       midorder(q->rchild);    

}

int main()

{

    int num;

    cin>>num;

    root=NULL;

    for(int i=1;i<=num;i++)

    {  

       string order;

       cin>>order;

       if(order=="insert")

       {

            int leaf;

            cin>>leaf;

            build(root,leaf);

       }

       else if(order=="find")

       {

            int puzzle;

            cin>>puzzle;

            find(root,puzzle);

            if(bianliang==1)cout<<"yes"<<endl;

            else if(bianliang==-1)cout<<"no"<<endl;

       }

       else if(order=="print")

       {

            midorder(root);

            cout<<endl;

            beforeorder(root);

            cout<<endl;

       } 

    }

    return 0;

}

