const ll N_MAX = 202020;



struct RAQSB{

	ll N;

	ll sN;

	ll data[N_MAX];

	ll bucket[N_MAX];



	RAQSB(ll n){

		sN = (ll)sqrt(n) + 1;

		N = sN * sN;

		REP(i, N_MAX){

			data[i] = 0;

			bucket[i] = 0;

		}

	}



	void add(ll s, ll t, ll x){

		ll ss = s/sN;

		ll tt = t/sN;

		if(ss==tt){

			for(int i=s;i<t;i++){

				data[i] += x;

			}

		}else{

			for(int i=s;i<(ss+1)*sN;i++){

				data[i] += x;

			}

			for(int i=tt*sN;i<t;i++){

				data[i] += x;

			}

			for(int i=ss+1;i<tt;i++){

				bucket[i] += x;

			}

		}

	}



	ll get_val(ll i){

		return data[i] + bucket[i/sN];

	}

};



